// Extrahiert den Next.js buildId aus der HTML-Response
const html = $input.first().json.data || $input.first().json;
const htmlStr = typeof html === 'string' ? html : JSON.stringify(html);

const match = htmlStr.match(/"buildId":"([^"]+)"/);
if (!match) {
  throw new Error('buildId konnte nicht aus HTML extrahiert werden — ist das SKOOL_COOKIE noch gültig?');
}

return [{ json: { buildId: match[1] } }];

// Extrahiert die 19 Courses und splittet sie in einzelne Items
const data = $input.first().json;
const courses = data.pageProps?.allCourses || [];
const buildId = $('BuildId extrahieren').first().json.buildId;

return courses.map(c => ({
  json: {
    buildId,
    courseId: c.id,
    courseSlug: c.name,
    courseTitle: c.metadata?.title,
    courseDesc: c.metadata?.desc || '',
    numModules: c.metadata?.numModules || 0,
    coverImage: c.metadata?.coverImage
  }
}));

// Extrahiert md aus __N_REDIRECT und bereitet nächsten Fetch vor.
// Input: Response vom Redirect-Fetch. Wir müssen courseSlug/buildId aus dem vorherigen Split-Node holen.

const items = $input.all();
const coursesFromSplit = $('Courses splitten').all();
const out = [];

for (let i = 0; i < items.length; i++) {
  const resp = items[i].json;
  const ctx = coursesFromSplit[i]?.json || {};
  const redirect = resp.pageProps?.__N_REDIRECT || '';
  const mdMatch = redirect.match(/md=([a-f0-9]+)/);

  if (!mdMatch) {
    // Course hat keinen Redirect → wahrscheinlich keine Module. Skip.
    continue;
  }

  out.push({
    json: {
      ...ctx,
      md: mdMatch[1]
    }
  });
}

return out;

// Aggregiert alle Course-Bäume zu flachen Arrays von Lessons/Chapters.
// Struktur (verifiziert):
//   pageProps.course.course = { ...course-metadaten }
//   pageProps.course.children = [{ course: {...unit}, children?: [...] }]
//   unit.unitType = 'module' (Lesson) | 'set' (Kapitel mit Sub-Modulen)

const items = $input.all();
const lessons = [];
const chapters = [];
const failed = [];

function walk(children, courseSlug, courseId, chapterId, sortBase) {
  children.forEach((wrapper, idx) => {
    const u = wrapper.course || {};
    const meta = u.metadata || {};
    const sortOrder = sortBase * 100 + idx;

    if (u.unitType === 'set') {
      chapters.push({
        skool_chapter_id: u.id,
        skool_course_slug: courseSlug,
        title: meta.title || '',
        description: meta.desc || '',
        sort_order: sortOrder
      });
      walk(wrapper.children || [], courseSlug, courseId, u.id, idx + 1);
    } else {
      // module = Lesson
      let resources = [];
      try {
        const rawResources = meta.resources;
        if (typeof rawResources === 'string' && rawResources.length > 2) {
          resources = JSON.parse(rawResources);
        } else if (Array.isArray(rawResources)) {
          resources = rawResources;
        }
      } catch(e) {}

      lessons.push({
        skool_lesson_id: u.id,
        skool_course_slug: courseSlug,
        skool_course_id: courseId,
        skool_chapter_id: chapterId || null,
        title: meta.title || '',
        description: meta.desc || '',
        sort_order: sortOrder,
        resources: resources,
        skool_url: `https://www.skool.com/ki-marketing-club/classroom/${courseSlug}?md=${u.id}`
      });
    }
  });
}

for (const item of items) {
  const data = item.json;
  const courseWrapper = data.pageProps?.course;
  if (!courseWrapper || !courseWrapper.course) {
    failed.push({ title: 'unknown', reason: 'Keine course-Daten im Response' });
    continue;
  }
  const course = courseWrapper.course;
  walk(courseWrapper.children || [], course.name, course.id, null, 0);
}

return [{ json: { lessons, chapters, failed, lessonCount: lessons.length, chapterCount: chapters.length } }];

// Diff: Skool vs. Supabase + Module-ID-Resolution
const skool = $('Lessons aggregieren').first().json;
const existingLessons = $('Existierende Lessons (DB)').all().map(i => i.json);
const existingChapters = $('Existierende Chapters (DB)').all().map(i => i.json);
const moduleMapping = $('Module-Mapping laden').all().map(i => i.json);

const existingLessonsMap = new Map(existingLessons.map(l => [l.skool_lesson_id, l]));
const existingChaptersMap = new Map(existingChapters.map(c => [c.skool_chapter_id, c]));
// Skool-Course-Slug → course_modules.id (UUID)
const moduleIdBySkoolSlug = new Map(moduleMapping.map(m => [m.skool_course_slug, m.id]));
// Skool-Chapter-ID → module_chapters.id (UUID), für chapter_id FK bei Lessons
const chapterIdBySkoolId = new Map(existingChapters.map(c => [c.skool_chapter_id, c.id]));

const report = {
  newChapters: [],
  newLessons: [],
  changedLessons: [],
  unchangedCount: 0,
  failed: skool.failed || []
};

// Chapters: neue ermitteln + module_id resolven
for (const ch of skool.chapters || []) {
  const moduleId = moduleIdBySkoolSlug.get(ch.skool_course_slug);
  if (!moduleId) {
    report.failed.push({ title: ch.title, reason: `Kein Mapping für Skool-Course '${ch.skool_course_slug}'` });
    continue;
  }
  if (!existingChaptersMap.has(ch.skool_chapter_id)) {
    report.newChapters.push({ ...ch, module_id: moduleId });
  }
}

// Lessons: neue ermitteln + module_id + chapter_id resolven
for (const l of skool.lessons || []) {
  const moduleId = moduleIdBySkoolSlug.get(l.skool_course_slug);
  if (!moduleId) {
    report.failed.push({ title: l.title, reason: `Kein Mapping für Skool-Course '${l.skool_course_slug}'`, skool_url: l.skool_url });
    continue;
  }
  const chapterId = l.skool_chapter_id ? chapterIdBySkoolId.get(l.skool_chapter_id) : null;
  const enriched = { ...l, module_id: moduleId, chapter_id: chapterId || null };

  const existing = existingLessonsMap.get(l.skool_lesson_id);
  if (!existing) {
    report.newLessons.push(enriched);
  } else if (existing.title !== l.title || existing.wistia_hashed_id === 'MISSING___' || !existing.skool_video_id && !existing.wistia_hashed_id) {
    // Re-fetch wenn: Title geändert ODER noch kein Wistia (Backfill skool_video_id)
    report.changedLessons.push({ ...enriched, _existing_id: existing.id });
  } else {
    report.unchangedCount++;
  }
}

return [{ json: report }];

// Fan-out: Neue Lessons als Drafts anlegen
const report = $input.first().json;
return (report.newLessons || []).map(l => ({ json: l }));

// Pro Item: Extrahiert aus Skool-Detail die echten Felder und konvertiert desc (PM-JSON v2) zu Markdown.

function pmToMarkdown(doc) {
  if (!doc) return '';

  function walkMarks(text, marks) {
    if (!marks?.length) return text;
    let out = text;
    for (const m of marks) {
      if (m.type === 'bold') out = `**${out}**`;
      else if (m.type === 'italic') out = `*${out}*`;
      else if (m.type === 'code') out = `\`${out}\``;
      else if (m.type === 'strike') out = `~~${out}~~`;
      else if (m.type === 'link') out = `[${out}](${m.attrs?.href || ''})`;
    }
    return out;
  }

  function walkNode(n, depth = 0) {
    if (!n) return '';
    const t = n.type;
    const content = (n.content || []).map(c => walkNode(c, depth)).join('');

    switch (t) {
      case 'text':
        return walkMarks(n.text || '', n.marks);
      case 'paragraph':
        return content + '\n\n';
      case 'heading': {
        const lvl = Math.min(Math.max(n.attrs?.level || 1, 1), 6);
        return '#'.repeat(lvl) + ' ' + content + '\n\n';
      }
      case 'bulletList':
        return (n.content || []).map(li => walkNode(li, depth + 1)).join('') + '\n';
      case 'orderedList':
        return (n.content || []).map((li, i) => walkNode(li, depth + 1).replace(/^- /, `${(n.attrs?.start || 1) + i}. `)).join('') + '\n';
      case 'listItem':
        return '- ' + (n.content || []).map(c => walkNode(c, depth + 1)).join('').trim() + '\n';
      case 'blockquote':
        return '> ' + content.trim().replace(/\n/g, '\n> ') + '\n\n';
      case 'codeBlock': {
        const lang = n.attrs?.language || '';
        return '```' + lang + '\n' + content + '\n```\n\n';
      }
      case 'horizontalRule':
        return '\n---\n\n';
      case 'hardBreak':
        return '  \n';
      case 'image': {
        const src = n.attrs?.src || '';
        const alt = n.attrs?.alt || '';
        return `![${alt}](${src})\n\n`;
      }
      default:
        return content;
    }
  }

  const arr = Array.isArray(doc) ? doc : [doc];
  return arr.map(n => walkNode(n)).join('').trim();
}

function parseSkoolDesc(raw) {
  if (!raw) return '';
  // Format: "[v2]<JSON>" or just plain text
  if (typeof raw !== 'string') return '';
  const m = raw.match(/^\[v2\](.*)$/s);
  if (!m) return raw;  // Plain text fallback
  try {
    const parsed = JSON.parse(m[1]);
    return pmToMarkdown(parsed);
  } catch (e) {
    return raw;
  }
}

function extractWistiaId(url) {
  if (!url) return null;
  const m = url.match(/wistia\.(?:com|net)\/(?:medias|embed\/iframe|embed\/channel\/[^/]+\/iframe)\/([a-z0-9]{10})/i);
  return m ? m[1] : null;
}

// Find the selected module in the returned tree
function findModule(items, targetId) {
  for (const it of items || []) {
    const c = it.course || {};
    if (c.id === targetId) return c;
    const sub = findModule(it.children, targetId);
    if (sub) return sub;
  }
  return null;
}

const items = $input.all();
const split = $('Neue Lessons splitten').all();
const out = [];

for (let i = 0; i < items.length; i++) {
  const resp = items[i].json;
  const ctx = split[i]?.json || {};
  const pp = resp.pageProps || {};
  const selected = pp.selectedModule;
  const mod = findModule(pp.course?.children || [], selected);

  if (!mod) {
    // Fallback: leeres Detail
    out.push({ json: { ...ctx, wistia_hashed_id: 'MISSING___', description_md: '', duration_seconds: null, resources: [] } });
    continue;
  }

  const meta = mod.metadata || {};
  const wistiaId = extractWistiaId(meta.videoLink) || 'MISSING___';
  let descMd = parseSkoolDesc(meta.desc);
  const durationMs = meta.videoLenMs || 0;
  const durationSec = durationMs ? Math.round(durationMs / 1000) : null;

  // Skool-natives Video (nicht Wistia) — prepend Hinweis in Description
  if (!wistiaId || wistiaId === 'MISSING___') {
    if (meta.videoId) {
      const note = `> 📹 **Skool-natives Video vorhanden** — muss manuell zu Wistia hochgeladen werden\n> Skool Video-ID: \`${meta.videoId}\`\n> [🔗 In Skool ansehen](${ctx.skool_url})\n\n---\n\n`;
      descMd = note + descMd;
    }
  }

  // Resources: Skool liefert {title, file_id, file_name, file_content_type}.
  // Direct-Download nicht möglich (signed CDN) — wir zeigen auf Skool-Lektion.
  let resources = [];
  try {
    const raw = meta.resources;
    const arr = typeof raw === 'string' ? JSON.parse(raw) : (Array.isArray(raw) ? raw : []);
    resources = arr.map((r, idx) => ({
      title: r.title || r.file_name || `Resource ${idx+1}`,
      url: ctx.skool_url,  // Point to Skool lesson for download
      resource_type: (r.file_content_type || '').includes('pdf') ? 'pdf' : 'link',
      sort_order: idx + 1,
      skool_resource_id: r.file_id || null
    }));
  } catch(e) {}

  out.push({
    json: {
      ...ctx,
      wistia_hashed_id: wistiaId,
      description_md: descMd,
      duration_seconds: durationSec,
      skool_video_id: meta.videoId || null,
      resources
    }
  });
}

return out;

// Fan-out: Neue Chapters als Drafts anlegen
const report = $input.first().json;
return (report.newChapters || []).map(c => ({ json: c }));

// Fan-out: Für jede neue Lesson → ihre Resources als einzelne Items.
// Input ist die Supabase-Create-Response (1 Item pro eingefügter Lesson inkl. id).
// Wir müssen den ursprünglichen Resources-Array über den vorherigen Code-Output verknüpfen.

const inserted = $input.all();
const parsed = $('Lesson-Detail parsen').all();
const out = [];

for (let i = 0; i < inserted.length; i++) {
  const lessonRow = inserted[i].json;  // Das ist das eben eingefügte module_videos-Zeile mit .id
  const ctx = parsed[i]?.json;
  if (!ctx || !ctx.resources?.length) continue;

  for (const r of ctx.resources) {
    out.push({
      json: {
        video_id: lessonRow.id,
        title: r.title,
        url: r.url,
        resource_type: r.resource_type,
        sort_order: r.sort_order,
        skool_resource_id: r.skool_resource_id
      }
    });
  }
}

return out;

// Fan-out: Geänderte Lessons für Detail-Fetch & Update
const report = $input.first().json;
return (report.changedLessons || []).map(l => ({ json: l }));

// Parser für Changed: gleiche Logik wie 'Lesson-Detail parsen', aber Kontext aus 'Geänderte Lessons splitten'

