  const m = raw.match(/^\[v2\](.*)$/s);
  if (!m) return raw;
  try { return pmToMarkdown(JSON.parse(m[1])); } catch(e) { return raw; }
}

function extractWistiaId(url) {
  if (!url) return null;
  const m = url.match(/wistia\.(?:com|net)\/(?:medias|embed\/iframe|embed\/channel\/[^/]+\/iframe)\/([a-z0-9]{10})/i);
  return m ? m[1] : null;
}

function findModule(items, targetId) {
  for (const it of items || []) {
    const c = it.course || {};
    if (c.id === targetId) return c;
    const sub = findModule(it.children, targetId);
    if (sub) return sub;
  }
  return null;
}

const items = $input.all();
const split = $('Geänderte Lessons splitten').all();
const out = [];

for (let i = 0; i < items.length; i++) {
  const resp = items[i].json;
  const ctx = split[i]?.json || {};
  const pp = resp.pageProps || {};
  const mod = findModule(pp.course?.children || [], pp.selectedModule);
  if (!mod) continue;

  const meta = mod.metadata || {};
  const wistiaId = extractWistiaId(meta.videoLink);
  let descMd = parseSkoolDesc(meta.desc);
  const durationMs = meta.videoLenMs || 0;
  const durationSec = durationMs ? Math.round(durationMs / 1000) : null;

  // Skool-natives Video hinweis in Desc
  if (!wistiaId && meta.videoId) {
    const note = `> 📹 **Skool-natives Video vorhanden** — muss manuell zu Wistia hochgeladen werden\n> Skool Video-ID: \`${meta.videoId}\`\n> [🔗 In Skool ansehen](${ctx.skool_url})\n\n---\n\n`;
    descMd = note + descMd;
  }

  out.push({
    json: {
      _existing_id: ctx._existing_id,
      title: ctx.title,
      description_md: descMd,
      duration_seconds: durationSec,
      sort_order: ctx.sort_order,
      skool_video_id: meta.videoId || null,
      wistia_hashed_id: wistiaId || 'MISSING___'
    }
  });
}

return out;

const report = $('Diff Skool ↔ DB').first().json;

const lines = [];
lines.push(`📚 *Skool-Sync Bericht — ${new Date().toLocaleDateString('de-DE')}*`);
lines.push('');

if (report.newLessons?.length) {
  lines.push(`✅ *Neu in Skool (${report.newLessons.length}):*`);
  report.newLessons.slice(0, 20).forEach(l => {
    lines.push(`  • ${l.title}`);
    lines.push(`    <${l.skool_url}|In Skool öffnen>`);
  });
  if (report.newLessons.length > 20) lines.push(`  … und ${report.newLessons.length - 20} weitere`);
  lines.push('');
}

if (report.newChapters?.length) {
  lines.push(`📂 *Neue Kapitel (${report.newChapters.length}):*`);
  report.newChapters.forEach(c => lines.push(`  • ${c.title}`));
  lines.push('');
}

if (report.changedLessons?.length) {
  lines.push(`🔄 *Geändert (${report.changedLessons.length}):*`);
  report.changedLessons.slice(0, 20).forEach(l => lines.push(`  • ${l.title}`));
  lines.push('');
}

if (report.failed?.length) {
  lines.push(`⚠️ *Konnte nicht übertragen werden (${report.failed.length}):*`);
  report.failed.forEach(f => lines.push(`  • ${f.title || f.reason}`));
  lines.push('');
}

lines.push(`🆗 Unverändert: ${report.unchangedCount || 0} Lektionen.`);
lines.push('');
lines.push(`👉 Drafts prüfen: https://herrtechgpt.de/admin/content/videos`);

return [{ json: { text: lines.join('\n') } }];
